parameters.functionCode:
const body = items[0].json.body;
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

return [
  {
    json: {
      platform: 'facebook_story',
      sender_id: messaging?.sender?.id || null,
      sender_name: null, // Facebook story replies don’t include name by default
      message: messaging?.message?.text || null,
      story_id: messaging?.message?.mid || null,
      received_at: messaging?.timestamp
        ? new Date(messaging.timestamp).toISOString()
        : new Date().toISOString(),
      status: 'pending',
      raw_payload: body
    }
  }
];

const hour = new Date().getUTCHours();

if (hour >= 6 && hour <= 14) {
  return [{ json: { ...$json, assigned_to: 'support_asia', status: 'assigned' } }];
}

if (hour > 14 && hour <= 22) {
  return [{ json: { ...$json, assigned_to: 'support_europe', status: 'assigned' } }];
}

return [{ json: { ...$json, status: 'unassigned' } }];

